// WF-15 §3.4 fix (Wave 1): switched parse_mode from "Markdown" → "HTML"
// because legacy Markdown has no backslash-escape and broke whenever a
// commit message contained `*`, `_`, `` ` ``, or `[` (e.g. "applyFizruk*").
// HTML only needs `&<>` escaped, which is trivial and bullet-proof.
//
// PR-16 (pr-plan-2026-05): added `terminal` boolean so the downstream IF
// node drops transient states (BUILDING / DEPLOYING / QUEUED /
// INITIALIZING / REMOVING / WAITING / CANCELLED / SKIPPED). Telegram
// тільки terminal-стани: SUCCESS / DEPLOYED / ACTIVE → ✅; FAILED /
// CRASHED → ❌. До цього кожен intermediate-статус слав
// false-positive «Deploy Failed», бо `ok` був true тільки для
// `[SUCCESS, DEPLOYED, ACTIVE]`, а решта (включно з BUILDING) показувалась
// як failure.
function htmlEscape(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}
const SUCCESS_TERMINAL = new Set(['SUCCESS', 'DEPLOYED', 'ACTIVE']);
const FAILED_TERMINAL = new Set(['FAILED', 'CRASHED']);
const root = $input.first().json;
const body = root.body ?? root;
const details = body.details ?? {};
const resource = body.resource ?? {};
const status = (details.status ?? body.status ?? body.type ?? 'UNKNOWN').toString();
const statusUpper = status.toUpperCase();
const service = resource.service?.name ?? body.service?.name ?? body.serviceName ?? '—';
const env = resource.environment?.name ?? body.environment?.name ?? body.environmentName ?? '—';
const branch = details.branch ?? body.deployment?.meta?.branch ?? body.branch ?? '—';
const commitMsg = (details.commitMessage ?? body.deployment?.meta?.commitMessage ?? body.commitMessage ?? '—').split('\n')[0];
const commitHash = (details.commitHash ?? body.deployment?.meta?.commitHash ?? body.commitHash ?? '').slice(0, 7);
const url = body.deployment?.url ?? body.deploymentUrl ?? '';
const duration = body.buildDuration ? `${Math.round(body.buildDuration / 1000)}s` : '—';
const ok = SUCCESS_TERMINAL.has(statusUpper);
const failed = FAILED_TERMINAL.has(statusUpper);
const terminal = ok || failed;
return [{ json: {
  status, service, env, branch, commitMsg, commitHash, url, duration, ok, failed, terminal,
  type: body.type ?? null,
  // _html-escaped variants for direct interpolation into the Telegram
  // node text — keep raw values around for downstream branches that may
  // want them un-escaped (alerts, future rich cards).
  serviceHtml: htmlEscape(service),
  envHtml: htmlEscape(env),
  branchHtml: htmlEscape(branch),
  commitMsgHtml: htmlEscape(commitMsg),
  commitHashHtml: htmlEscape(commitHash),
  durationHtml: htmlEscape(duration),
  urlHtml: htmlEscape(url),
} }];

// ADR-0038, Wave 3 §3.2 — pre-Telegram step that builds a stable
// `alertId` so n8n retries no-op via ON CONFLICT DO NOTHING.
// Topic is dynamic: success → ops/P2, failure → incidents/P1.
const parsed = $input.first()?.json ?? {};
const alertId = `${$workflow.id || 'wf15'}:${$execution.id || 'unknown'}:railway-${parsed.branch || 'unknown'}-${parsed.commitHash || 'unknown'}`;
const topic = parsed.ok ? 'ops' : 'incidents';
const severity = parsed.ok ? 'P2' : 'P1';
const summary = parsed.ok
  ? `Railway deploy OK — ${parsed.service || '?'} (${parsed.env || '?'}) @ ${parsed.commitHash || '?'}`
  : `Railway deploy FAILED — ${parsed.service || '?'} (${parsed.env || '?'}) @ ${parsed.commitHash || '?'}`;
return [{
  json: {
    ...parsed,
    alertId,
    topic,
    severity,
    alertSummary: summary,
    alertMetadata: {
      workflowId: $workflow.id || 'unknown',
      executionId: $execution.id || 'unknown',
      service: parsed.service ?? null,
      env: parsed.env ?? null,
      branch: parsed.branch ?? null,
      commitHash: parsed.commitHash ?? null,
      ok: Boolean(parsed.ok),
      status: parsed.status ?? null,
    },
  },
}];
